6},{"word":"of","start":150.16,"end":150.44},{"word":"mine","start":150.44,"end":151.4},{"word":"my","start":151.42,"end":152.66},{"word":"angel","start":152.66,"end":152.66},{"word":"from","start":152.66,"end":153.28},{"word":"above","start":153.28,"end":154.08},{"word":"No","start":154.08,"end":154.6},{"word":"one","start":154.6,"end":155.26},{"word":"else","start":155.26,"end":155.82},{"word":"is","start":155.82,"end":156.04},{"word":"like","start":156.04,"end":156.68},{"word":"you","start":156.68,"end":157.34},{"word":"the","start":157.34,"end":157.94},{"word":"first","start":157.94,"end":158.28},{"word":"woman","start":158.28,"end":159.0},{"word":"I","start":159.0,"end":159.46},{"word":"ever","start":159.46,"end":159.86},{"word":"loved","start":159.86,"end":160.58},{"word":"I","start":160.98,"end":161.56},{"word":"hope","start":161.56,"end":161.98},{"word":"I","start":161.98,"end":162.42},{"word":"make","start":162.42,"end":162.8},{"word":"you","start":162.8,"end":164.0},{"word":"proud","start":164.0,"end":164.0},{"word":"for","start":164.0,"end":164.84},{"word":"all","start":164.84,"end":165.42},{"word":"that","start":165.42,"end":165.66},{"word":"you","start":165.66,"end":165.96},{"word":"have","start":165.96,"end":166.4},{"word":"done","start":166.4,"end":166.7},{"word":"I''ll","start":166.7,"end":167.5},{"word":"always","start":167.5,"end":168.1},{"word":"be","start":168.1,"end":168.82},{"word":"forever","start":168.82,"end":169.4},{"word":"grateful","start":169.4,"end":170.46},{"word":"to","start":170.46,"end":172.4},{"word":"the","start":172.4,"end":172.64},{"word":"first","start":172.64,"end":173.1},{"word":"woman","start":173.1,"end":173.98},{"word":"I","start":173.98,"end":175.46},{"word":"ever","start":175.46,"end":175.86},{"word":"loved","start":175.86,"end":178.56},{"word":"I''ll","start":182.22,"end":183.62},{"word":"always","start":183.62,"end":183.98},{"word":"remember","start":183.98,"end":184.52},{"word":"I","start":184.52,"end":185.46},{"word":"love","start":185.46,"end":186.28},{"word":"you","start":186.28,"end":186.98},{"word":"From","start":188.46,"end":189.86},{"word":"now","start":189.86,"end":190.44},{"word":"through","start":190.44,"end":192.4},{"word":"eternity","start":192.4,"end":193.56}],"lines":[{"text":"I will never forget the one who loved and cared for me","start":0.0,"end":18.26},{"text":"The one who taught me right from wrong and saw the man","start":19.02,"end":23.66},{"text":"I''d be","start":23.66,"end":24.68},{"text":"When the world felt cold and empty you were steady as the","start":25.04,"end":30.42},{"text":"sun You gave me strength to keep on going before my life","start":30.42,"end":35.82},{"text":"had even begun","start":35.82,"end":37.4},{"text":"As the days rolled by","start":37.98,"end":39.9},{"text":"you were there day by day","start":41.02,"end":44.2},{"text":"Encouraging me","start":44.58,"end":46.38},{"text":"loving me pointing me on my way","start":46.82,"end":50.44},{"text":"When I was just a little boy trying hard to understand You","start":50.93,"end":56.98},{"text":"were the arms that held me close and the heart that made","start":56.98,"end":61.52},{"text":"me a man This mother of mine my angel from above No","start":61.52,"end":68.48},{"text":"one else is like you","start":68.48,"end":70.84},{"text":"the first woman I ever loved I hope I make you proud","start":71.2,"end":77.62},{"text":"for all that you have done I''ll always be forever grateful to","start":77.62,"end":86.0},{"text":"the first woman I ever loved","start":86.0,"end":91.0},{"text":"The years go by so fast and change comes suddenly","start":95.64,"end":100.2},{"text":"But one thing that will never fade is what you mean to","start":101.66,"end":107.06},{"text":"me The best in me is from you the truth still shines","start":107.06,"end":113.1},{"text":"so clear And I will always carry your love through every passing","start":113.1,"end":119.9},{"text":"year Thank you my mother for this life you gave me","start":119.9,"end":126.24},{"text":"Thank you my mother for the home you made for me Thank","start":126.88,"end":133.78},{"text":"you my mother","start":133.78,"end":135.36},{"text":"for every word that lived in me Thank you my mother for","start":135.94,"end":143.88},{"text":"all the love you gave to me","start":143.88,"end":148.16},{"text":"This mother of mine my angel from above No one else is","start":148.96,"end":156.04},{"text":"like you the first woman I ever loved","start":156.04,"end":160.58},{"text":"I hope I make you proud for all that you have done","start":160.98,"end":166.7},{"text":"I''ll always be forever grateful to the first woman I ever loved","start":166.7,"end":178.56},{"text":"I''ll always remember I love you","start":182.22,"end":186.98},{"text":"From now through eternity","start":188.46,"end":193.56}],"duration":193.56,"plain_text":"I will never forget the one who loved and cared for me The one who taught me right from wrong and saw the man I''d be When the world felt cold and empty, you were steady as the sun You gave me strength to keep on going before my life had even begun As the days rolled by, you were there day by day Encouraging me, loving me, pointing me on my way When I was just a little boy, trying hard to understand You were the arms that held me close and the heart that made me a man This mother of mine, my angel from above No one else is like you, the first woman I ever loved I hope I make you proud for all that you have done I''ll always be forever grateful to the first woman I ever loved The years go by so fast and change comes suddenly But one thing that will never fade is what you mean to me The best in me is from you, the truth still shines so clear And I will always carry your love through every passing year Thank you, my mother, for this life you gave me Thank you, my mother, for the home you made for me Thank you, my mother, for every word that lived in me Thank you, my mother, for all the love you gave to me This mother of mine, my angel from above No one else is like you, the first woman I ever loved I hope I make you proud for all that you have done I''ll always be forever grateful to the first woman I ever loved I''ll always remember I love you From now through eternity"}', transcript_state = 'ready', updated_at = CURRENT_TIMESTAMP WHERE slug = 'the-first-woman-i-ever-loved';

